"use strict";(self.webpackChunkpims_manual=self.webpackChunkpims_manual||[]).push([[7893],{7275:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>c,contentTitle:()=>s,default:()=>h,frontMatter:()=>i,metadata:()=>r,toc:()=>d});var o=n(4848),a=n(8453);const i={},s="Appendix S \u2013 Family Educational Rights and Privacy Act",r={id:"appendix/appendix-S",title:"Appendix S \u2013 Family Educational Rights and Privacy Act",description:"Student education records are official and confidential documents protected by one of the nation's strongest privacy protection laws, the Family Educational Rights and Privacy Act (FERPA). FERPA, also known as the Buckley Amendment, defines education records as all records that schools or education agencies maintain about students.",source:"@site/docs/appendix/appendix-S.mdx",sourceDirName:"appendix",slug:"/appendix/appendix-S",permalink:"/docs/appendix/appendix-S",draft:!1,unlisted:!1,editUrl:"https://github.com/Bwest8/pimsKB/tree/master/docs/appendix/appendix-S.mdx",tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Appendix R \u2013 Calendar Program Codes",permalink:"/docs/appendix/appendix-R"},next:{title:"Appendix U \u2013 Educational Environment",permalink:"/docs/appendix/appendix-U"}},c={},d=[{value:"FERPA Protects Privacy",id:"ferpa-protects-privacy",level:2},{value:"FERPA Defines an Education Record",id:"ferpa-defines-an-education-record",level:2},{value:"FERPA Guarantees Parent Review and Appeal",id:"ferpa-guarantees-parent-review-and-appeal",level:2},{value:"FERPA Restricts Disclosure of Student Records",id:"ferpa-restricts-disclosure-of-student-records",level:2},{value:"Additional FERPA Provisions",id:"additional-ferpa-provisions",level:2},{value:"Questions?",id:"questions",level:2}];function l(e){const t={h1:"h1",h2:"h2",li:"li",p:"p",strong:"strong",ul:"ul",...(0,a.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.h1,{id:"appendix-s--family-educational-rights-and-privacy-act",children:"Appendix S \u2013 Family Educational Rights and Privacy Act"}),"\n",(0,o.jsx)(t.p,{children:"Student education records are official and confidential documents protected by one of the nation's strongest privacy protection laws, the Family Educational Rights and Privacy Act (FERPA). FERPA, also known as the Buckley Amendment, defines education records as all records that schools or education agencies maintain about students."}),"\n",(0,o.jsx)(t.p,{children:'FERPA gives parents (as well as students in postsecondary schools) the right to review and confirm the accuracy of education records. This and other United States "privacy" laws ensure that information about citizens collected by schools and government agencies can be released only for specific and legally defined purposes. Since enacting FERPA in 1974, Congress has strengthened privacy safeguards of education records through this law, refining and clarifying family rights and agency responsibilities to protect those rights.'}),"\n",(0,o.jsx)(t.p,{children:"FERPA's legal statute citation can be found in the U.S. Code (20 USC 1232g), which incorporates all amendments to FERPA. FERPA regulations are found in the Federal Register (34 CFR Part 99). FERPA's 1994 amendments are found in Public Law (PL) 103382."}),"\n",(0,o.jsx)(t.h2,{id:"ferpa-protects-privacy",children:"FERPA Protects Privacy"}),"\n",(0,o.jsx)(t.p,{children:"FERPA applies to public schools and state or local education agencies that receive Federal education funds, and it protects both paper and computerized records. In addition to the Federal laws that restrict disclosure of information from student records, most states also have privacy protection laws that reinforce FERPA. State laws can supplement FERPA, but compliance with FERPA is necessary for schools to be eligible to receive Federal education funds."}),"\n",(0,o.jsx)(t.p,{children:'FERPA requires schools and local education agencies to have written and accessible policies about how they restrict the release of student records. The policies must explain parents\' rights under FERPA, define what qualifies as "directory information" (personal information that can be made public), set procedures for reviewing and correcting records, and explain how and when student information can be disclosed. When students reach the age of 18, or when they become students at postsecondary education institutions, rights under FERPA transfer from the parents to the students.'}),"\n",(0,o.jsx)(t.p,{children:"FERPA gives both parents, custodial and non-custodial, equal access to student information unless the school has evidence of a court order or state law revoking these rights."}),"\n",(0,o.jsx)(t.h2,{id:"ferpa-defines-an-education-record",children:"FERPA Defines an Education Record"}),"\n",(0,o.jsx)(t.p,{children:"Education records include a range of information about a student that is collected in schools, such as:"}),"\n",(0,o.jsx)(t.p,{children:"date and place of birth; parent(s) and/or guardian addresses; where parents can be contacted in emergencies; grades; test scores; courses taken; academic specializations and activities; official letters regarding a student's status in school; Special Education records; disciplinary records; medical and health records that the school creates or collects and maintains; documentation of attendance; schools attended; courses taken; awards conferred; and degrees earned; personal information such as a student's state-provided identification number, picture, or other information that would make it easy to identify or locate a student."}),"\n",(0,o.jsx)(t.p,{children:"Personal notes made by teachers and other school officials that are not shared with others are not considered education records. Additionally, law enforcement records created and maintained by a school or district's law enforcement unit are not education records."}),"\n",(0,o.jsxs)(t.p,{children:["Part of the education record, known as ",(0,o.jsx)(t.strong,{children:"directory information"}),", includes personal information about a student that can be made public according to a school system's FERPA policy. Directory information may include a student's name, address, and telephone number, and other information typically found in school yearbooks or athletic programs. Other examples are names and pictures of participants in various extracurricular activities or recipients of awards, pictures of students, and height and weight of athletes."]}),"\n",(0,o.jsx)(t.p,{children:"Each year schools must give parents public notice of the types of information designated as directory information. By a specified time after parents are notified of their review rights, parents may ask to remove all or part of the information on their child that they do not wish to be available to the public without their consent."}),"\n",(0,o.jsx)(t.h2,{id:"ferpa-guarantees-parent-review-and-appeal",children:"FERPA Guarantees Parent Review and Appeal"}),"\n",(0,o.jsx)(t.p,{children:"If, upon review, parents find an education record is inaccurate or misleading, they may request changes or corrections, and schools and education agencies must respond promptly to these requests."}),"\n",(0,o.jsx)(t.p,{children:"Requests should be made in writing according to local policies. Within a reasonable time period, the school or agency must decide if the request to change the record is consistent with its own assessment of the accuracy of the record. If a parent's request is denied, they must be offered the opportunity for a hearing. If parents' disagreement with the record continues after the hearing, they may insert an explanation of their objection in the record."}),"\n",(0,o.jsx)(t.p,{children:"FERPA's provisions do not apply to grades and educational decisions about children that school personnel make."}),"\n",(0,o.jsx)(t.p,{children:"While parents have a right to review records, schools are not required by federal law to provide copies of information, unless providing copies would be the only way of giving parents access. Schools may charge a reasonable fee for obtaining records, and they may not destroy records if a request for access is pending."}),"\n",(0,o.jsx)(t.h2,{id:"ferpa-restricts-disclosure-of-student-records",children:"FERPA Restricts Disclosure of Student Records"}),"\n",(0,o.jsx)(t.p,{children:"Local education agencies and schools may release information from students' education records with the prior written consent of parents, under limited conditions specified by law, and as stated in local agencies' student records policies. The same rules restricting disclosures apply to records maintained by third parties acting on behalf of schools, such as state and local education agencies, intermediate administrative units, researchers, psychologists, or medical practitioners who work for or are under contract to schools."}),"\n",(0,o.jsx)(t.p,{children:"A school district is required, however, to have a policy that specifies the categories of officials and parties to whom records may be released without parental consent. The policy should be readily accessible to parents for review."}),"\n",(0,o.jsx)(t.p,{children:"Teachers and school officials who work with the students and schools to which students apply for entrance may also have access to education records without parental consent. In addition, information from students' records may be released to State and local education officials to conduct audits or to review records in compliance with Federal laws. Schools may also disclose information from education records without the consent of parents in response to subpoenas or court orders. A school official must make a reasonable effort to notify the parent before complying with the subpoena unless the subpoena is issued to enforce a law and specifies not to notify the parent."}),"\n",(0,o.jsx)(t.p,{children:"In emergencies, school officials can provide information from education records to protect the health or safety of the student or others."}),"\n",(0,o.jsx)(t.p,{children:"There are cases when schools or school systems decide it is in the public interest to participate in policy evaluations or research studies. If student records are to be released for these purposes, the school or school system must obtain prior parent consent. Signed and dated written consent must:"}),"\n",(0,o.jsxs)(t.ul,{children:["\n",(0,o.jsx)(t.li,{children:"specify the records that will be released;"}),"\n",(0,o.jsx)(t.li,{children:"state the reason for releasing the records; and"}),"\n",(0,o.jsx)(t.li,{children:"identify the groups or individuals who will receive the records."}),"\n"]}),"\n",(0,o.jsx)(t.p,{children:"In general, information about each request for records access and each disclosure of information from an education record must be maintained as part of the record until the school or agency destroys the education record. Outside parties receiving records must receive a written explanation of the restrictions on the rerelease of information."}),"\n",(0,o.jsx)(t.h2,{id:"additional-ferpa-provisions",children:"Additional FERPA Provisions"}),"\n",(0,o.jsx)(t.p,{children:"In 1994, the Improving America's Schools Act amended several components of FERPA, tightening privacy assurances for students and families. The amendments apply to the following key areas:"}),"\n",(0,o.jsxs)(t.ul,{children:["\n",(0,o.jsx)(t.li,{children:"parents have the right to review the education records of their children maintained by state education agencies;"}),"\n",(0,o.jsx)(t.li,{children:"any agency or institution that inappropriately re-releases personally identifiable information from an education record cannot have access to education records for five years;"}),"\n",(0,o.jsx)(t.li,{children:"information about disciplinary actions taken against students may be shared, without parents' consent, with officials in other education institutions; and"}),"\n",(0,o.jsx)(t.li,{children:"schools may release records in compliance with certain law enforcement judicial orders and subpoenas without notifying parents."}),"\n"]}),"\n",(0,o.jsx)(t.h2,{id:"questions",children:"Questions?"}),"\n",(0,o.jsx)(t.p,{children:"Call your local school system, state agency, or the Family Policy Compliance Office."}),"\n",(0,o.jsx)(t.p,{children:"School districts, state education agencies, and the U.S. Department of Education offer assistance about FERPA. Before contacting federal officials, you can often get a direct and immediate response from your local or state education officials."})]})}function h(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(l,{...e})}):l(e)}},8453:(e,t,n)=>{n.d(t,{R:()=>s,x:()=>r});var o=n(6540);const a={},i=o.createContext(a);function s(e){const t=o.useContext(i);return o.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),o.createElement(i.Provider,{value:t},e.children)}}}]);